using System;using System.Collections.Generic;using System.IO;using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.Templates{    /// <summary>    /// 模板信息    /// </summary>    public class TemplateInfo    {        /// <summary>        /// 模板名称        /// </summary>        public string Name { get; set; }                /// <summary>        /// 模板描述        /// </summary>        public string Description { get; set; }                /// <summary>        /// 模板文件路径        /// </summary>        public string Path { get; set; }                /// <summary>        /// 模板类型        /// </summary>        public string Type { get; set; }    }        /// <summary>    /// 模板管理器    /// </summary>    public class TemplateManager    {        private readonly List<TemplateInfo> _templates = new List<TemplateInfo>();        private readonly DesignContext _context;                /// <summary>        /// 模板集合        /// </summary>        public IReadOnlyList<TemplateInfo> Templates => _templates.AsReadOnly();                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public TemplateManager(DesignContext context)        {            _context = context;            // 加载内置模板            LoadBuiltInTemplates();        }                /// <summary>        /// 加载内置模板        /// </summary>        private void LoadBuiltInTemplates()        {            // 添加默认模板            _templates.Add(new TemplateInfo            {                Name = "空白模板",                Description = "空白的设计模板",                Path = null,                Type = "空白"            });                        // 可以在这里添加其他内置模板        }                /// <summary>        /// 加载模板目录        /// </summary>        /// <param name="templateDirectory">模板目录</param>        public void LoadTemplates(string templateDirectory)        {            if (!Directory.Exists(templateDirectory))            {                Directory.CreateDirectory(templateDirectory);                return;            }                        var templateFiles = Directory.GetFiles(templateDirectory, "*.xml");            foreach (var file in templateFiles)            {                try                {                    // 尝试加载模板文件以获取模板信息                    var templateInfo = new TemplateInfo                    {                        Name = Path.GetFileNameWithoutExtension(file),                        Description = "自定义模板",                        Path = file,                        Type = "自定义"                    };                                        _templates.Add(templateInfo);                }                catch (Exception ex)                {                    Console.WriteLine($"加载模板文件 {file} 失败: {ex.Message}");                }            }        }                /// <summary>        /// 应用模板        /// </summary>        /// <param name="template">模板信息</param>        /// <returns>是否应用成功</returns>        public bool ApplyTemplate(TemplateInfo template)        {            if (template == null || string.IsNullOrEmpty(template.Path))                return false;                        try            {                // 加载模板文件                using (var reader = System.Xml.XmlReader.Create(template.Path))                {                    var loadSettings = new ICSharpCode.WpfDesign.Designer.Xaml.XamlLoadSettings();                    var templateContext = new ICSharpCode.WpfDesign.Designer.Xaml.XamlDesignContext(reader, loadSettings);                                        // 复制模板内容到当前设计上下文                    if (templateContext.RootItem != null)                    {                        // 清除当前设计内容                        _context.RootItem.CollectionElements.Clear();                                                // 添加模板内容                        foreach (var child in templateContext.RootItem.CollectionElements)                        {                            _context.RootItem.CollectionElements.Add(child);                        }                                                return true;                    }                }            }            catch (Exception ex)            {                Console.WriteLine($"应用模板 {template.Name} 失败: {ex.Message}");            }                        return false;        }                /// <summary>        /// 保存模板        /// </summary>        /// <param name="name">模板名称</param>        /// <param name="description">模板描述</param>        /// <param name="path">保存路径</param>        /// <returns>是否保存成功</returns>        public bool SaveTemplate(string name, string description, string path)        {            try            {                // 保存当前设计内容为模板                using (var writer = System.Xml.XmlWriter.Create(path, new System.Xml.XmlWriterSettings { Indent = true }))                {                    _context.Save(writer);                }                                // 添加到模板列表                var templateInfo = new TemplateInfo                {                    Name = name,                    Description = description,                    Path = path,                    Type = "自定义"                };                                _templates.Add(templateInfo);                return true;            }            catch (Exception ex)            {                Console.WriteLine($"保存模板 {name} 失败: {ex.Message}");                return false;            }        }                /// <summary>        /// 获取模板        /// </summary>        /// <param name="name">模板名称</param>        /// <returns>模板信息</returns>        public TemplateInfo GetTemplate(string name)        {            return _templates.Find(t => t.Name == name);        }                /// <summary>        /// 按类型获取模板        /// </summary>        /// <param name="type">模板类型</param>        /// <returns>模板信息列表</returns>        public List<TemplateInfo> GetTemplatesByType(string type)        {            return _templates.FindAll(t => t.Type == type);        }    }}